export function getAvailableCategories() {
  return [...Object.keys(NEWS_XMLS)];
}

const decodeHtmlEntities = (value) => {
  return value
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, " ");
};

const stripHtmlTags = (value) => value.replace(/<[^>]+>/g, "").trim();

const extractTag = (xml, tagName) => {
  const startTag = `<${tagName}>`;
  const endTag = `</${tagName}>`;
  const startIndex = xml.indexOf(startTag);
  if (startIndex === -1) return "";

  const endIndex = xml.indexOf(endTag, startIndex);
  if (endIndex === -1) return "";

  let content = xml.substring(startIndex + startTag.length, endIndex).trim();

  if (content.startsWith("<![CDATA[") && content.endsWith("]]>")) {
    content = content.substring(9, content.length - 3);
  }

  return decodeHtmlEntities(stripHtmlTags(content));
};

const extractMediaUrl = (xml) => {
  const mediaContentStart = xml.indexOf("<media:content");
  if (mediaContentStart === -1) return "";

  const urlMatch = xml
    .substring(mediaContentStart, mediaContentStart + 200)
    .match(/url="([^"]+)"/);
  return urlMatch ? urlMatch[1] : "";
};

const parseRssItems = (xmlText, rssUrl) => {
  const items = [];
  const itemStart = xmlText.indexOf("<item>");
  if (itemStart === -1) return items;

  let remaining = xmlText.substring(itemStart);
  let itemCount = 0;

  while (remaining.includes("<item>") && itemCount < 50) {
    const itemEnd = remaining.indexOf("</item>") + 7;
    if (itemEnd === 6) break;

    const itemText = remaining.substring(0, itemEnd);
    remaining = remaining.substring(itemEnd);

    const title = extractTag(itemText, "title");
    const link = extractTag(itemText, "link");
    const timestampRaw = extractTag(itemText, "timestamp");
    const pubDate = extractTag(itemText, "pubDate");
    
    let timestamp;
    if (timestampRaw && timestampRaw.length === 14) {
      const parts = timestampRaw.match(/(\d{4})(\d{2})(\d{2})(\d{2})(\d{2})(\d{2})/);
      if (parts) {
        // Meses en JS son 0-11
        timestamp = new Date(
          parseInt(parts[1]), 
          parseInt(parts[2]) - 1, 
          parseInt(parts[3]), 
          parseInt(parts[4]), 
          parseInt(parts[5]), 
          parseInt(parts[6])
        );
      }
    }
    
    if (!timestamp || isNaN(timestamp.getTime())) {
      timestamp = pubDate ? new Date(pubDate) : new Date();
      if (isNaN(timestamp.getTime())) {
        timestamp = new Date();
      }
    }

    const description = extractTag(itemText, "description") || extractTag(itemText, "descent") || extractTag(itemText, "content:encoded");
    const imageUrl = extractMediaUrl(itemText);

    const year = new Date().getFullYear(); 
    const month = new Date().getMonth();
    if (title && link) {
      items.push({
        title,
        link,
        timestamp: timestamp ? timestamp : pubDate,
        description,
        imageUrl,
      });
    }

    itemCount++;
  }

  return items;
};

export async function fetchNewsFromRss(category) {
  try {
    if (!NEWS_XMLS[category]) {
      throw new Error(`Categoría no válida: ${category}`);
    }

    const rssUrls = NEWS_XMLS[category];
    const itemsAll = [];

    for (const rssUrl of rssUrls) {
      try {
        const response = await fetch(rssUrl, { cache: "no-store" });

        if (!response.ok) {
          console.warn(`Error en RSS ${rssUrl}: ${response.status}`);
          continue;
        }

        const text = await response.text();
        const items = parseRssItems(text, rssUrl);
        itemsAll.push(...items);
      } catch (error) {
        console.error(`Error fetching RSS ${rssUrl} for ${category}:`, error);
      }
    }

    if (itemsAll.length === 0) {
      throw new Error(`No se pudieron obtener noticias de ningún RSS para la categoría ${category}`);
    }

    return itemsAll;
  } catch (error) {
    console.error(`Error fetching RSS for ${category}:`, error);
    throw error;
  }
}

export async function getLatestNewDate(category) {
  if (!category) return null;
  const result = await query(
    `SELECT MAX(timestamp) as last_date 
    FROM news 
    WHERE category = $1;`, [category]);

  return result.rows?.[0]?.last_date || null;
}

export async function syncNewsToDatabase(category) {
  try {
      // OPTIMIZACIÓN: Solo descargar del RSS si no hay noticias previas 
      // o si queremos forzar una actualización (podríamos añadir un check de tiempo aquí)
      let items = [];
      try {
        items = await fetchNewsFromRss(category);
      } catch (error) {
        // Si el error es un 404 o similar del RSS, lo logueamos pero no detenemos la sincronización global
        console.warn(`Saltando categoría ${category} debido a error de RSS: ${error.message}`);
        return 0;
      }


    if (!items || items.length === 0) {
      return 0;
    }


    let insertedCount = 0;

    for (const item of items) {
      try {
        if (!item.link) {
          console.warn(`Saltando noticia sin link en categoría ${category}`);
          continue;
        }

        const result = await query(
          `INSERT INTO news (title, description, link, timestamp, image_url, category)
           VALUES ($1, $2, $3, $4, $5, $6)
           ON CONFLICT (link) DO NOTHING;`,
          [
            item.title || "Sin título",
            item.description || "",
            item.link,
            item.timestamp || new Date(),
            item.imageUrl || "",
            category,
          ]
        );

        if (result.rowCount > 0) {
          insertedCount++;
        }
      } catch (error) {
        console.error(`Error insertando noticia [${item.link}]:`, error);
      }
    }
    return insertedCount;
  } catch (error) {
    console.error(`Error sincronizando ${category}:`, error);
    throw error;
  }
}

export async function syncAllNews() {
  console.log("Sincronizando base de datos");

  const categories = Object.keys(NEWS_XMLS);
  const results = {};

  for (const category of categories) {
    try {
      results[category] = await syncNewsToDatabase(category);
    } catch (error) {
      console.error(`Error al cargar categoría ${category}:`, error);
      results[category] = 0;
    }
  }
  console.log("Sincronizacion completa");
  return results;
}

export async function getNewsFromDatabase(filters = {}, limit = 50, offset = 0) {
  try {
    const { categories, startDate, endDate } = filters;
    let sql = `SELECT * FROM news`;
    const params = [];
    const conditions = [];
    
    if (categories && Array.isArray(categories) && categories.length > 0) {
      if (categories.length > 1) {
        conditions.push(`category = ANY($${params.length + 1})`);
        params.push(categories);
      } else {
        conditions.push(`category = $${params.length + 1}`);
        params.push(categories[0]);
      }
    }

    if (startDate) {
      conditions.push(`timestamp >= $${params.length + 1}`);
      const start = new Date(startDate);
      start.setHours(0, 0, 0, 0);
      params.push(start);
    }

    if (endDate) {
      conditions.push(`timestamp < $${params.length + 1}`);
      const end = new Date(endDate);
      end.setDate(end.getDate() + 1);
      params.push(end);
    }

    if (conditions.length > 0) {
      sql += ` WHERE ` + conditions.join(' AND ');
    }

    sql += ` ORDER BY timestamp DESC LIMIT $${params.length + 1} OFFSET $${params.length + 2}`;
    params.push(limit, offset);

    const result = await query(sql, params);
    return result.rows;
  } catch (error) {
    console.error("Error obteniendo noticias de BD:", error);
    return [];
  }
}

